using System;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    public TestContext TestContext { get; set; }

    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    [TestMethod]
    public void CalculateTotal_WithValidInputs_ReturnsSubtotalPlusTax()
    {
        var result = _calculator.CalculateTotal(10m, 2, 0.1m);
        Assert.AreEqual(22m, result);
    }

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));
        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void FormatPrice_DefaultSymbol_ReturnsFormattedString()
    {
        object result = _calculator.FormatPrice(9.99m);
        var str = Assert.IsInstanceOfType<string>(result);
        Assert.Contains("9.99", str);
    }

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        Assert.AreEqual(expected, _calculator.ApplyDiscount(price, discountPercent));
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
    ];
}

